import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

const BG_IMAGES = ['/library-bg.jpg'];

export default function Login() {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [error, setError]       = useState('');
  const [loading, setLoading]   = useState(false);
  const [showPass, setShowPass] = useState(false);
  const [scale, setScale]       = useState(1);
  const [imgLoaded, setImgLoaded] = useState(false);
  const { login } = useAuth();
  const navigate  = useNavigate();

  /* Ken Burns zoom-in / zoom-out effect */
  useEffect(() => {
    let dir = 1;
    const interval = setInterval(() => {
      setScale(s => {
        const next = s + dir * 0.0008;
        if (next >= 1.12) dir = -1;
        if (next <= 1.00) dir = 1;
        return parseFloat(next.toFixed(4));
      });
    }, 30);
    return () => clearInterval(interval);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await login(email, password);
      navigate('/dashboard');
    } catch (e: any) {
      setError(e.response?.data?.message || 'Invalid email or password');
    } finally { setLoading(false); }
  };

  return (
    <div style={{
      minHeight: '100vh', width: '100%',
      position: 'relative', display: 'flex',
      alignItems: 'center', justifyContent: 'center',
      fontFamily: "'DM Sans', sans-serif",
      overflow: 'hidden',
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@600;700&family=DM+Sans:wght@400;500;600;700&display=swap');

        * { box-sizing: border-box; }

        .li { border-radius: 12px; transition: border-color .2s, box-shadow .2s; }
        .li:focus { border-color: #c9a84c !important; box-shadow: 0 0 0 3px rgba(201,168,76,0.2) !important; outline: none; }
        .li::placeholder { color: rgba(255,255,255,0.25) !important; }

        .btn-sign:hover:not(:disabled) {
          background: #d4b55a !important;
          transform: translateY(-2px);
          box-shadow: 0 10px 30px rgba(201,168,76,0.45) !important;
        }
        .btn-sign:active { transform: translateY(0) !important; }
        .btn-sign:disabled { opacity: .65; cursor: not-allowed; }

        .card-enter { animation: cardUp .6s cubic-bezier(.16,1,.3,1) forwards; }
        @keyframes cardUp {
          from { opacity:0; transform:translateY(30px) scale(.97); }
          to   { opacity:1; transform:translateY(0)   scale(1);    }
        }

        .fade-in { animation: fi .8s ease forwards; }
        @keyframes fi { from { opacity:0; } to { opacity:1; } }

        a.reg-link { color: #c9a84c; font-weight:600; text-decoration:none; transition: opacity .2s; }
        a.reg-link:hover { opacity: .75; }

        .eye-btn { position:absolute; right:14px; top:50%; transform:translateY(-50%); background:none; border:none; cursor:pointer; color:rgba(255,255,255,0.4); font-size:17px; padding:4px; line-height:1; transition: color .2s; }
        .eye-btn:hover { color:rgba(255,255,255,0.8); }
      `}</style>

      {/* ── Background image with Ken Burns ── */}
      <div style={{
        position: 'absolute', inset: 0, zIndex: 0,
        backgroundImage: 'url(/library-bg.jpg)',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        transform: `scale(${scale})`,
        filter: 'brightness(0.45)',
        willChange: 'transform',
        transition: 'transform .1s linear',
      }} />

      {/* ── Vignette overlay ── */}
      <div style={{
        position: 'absolute', inset: 0, zIndex: 1,
        background: 'radial-gradient(ellipse at center, transparent 30%, rgba(0,0,0,0.65) 100%)',
      }} />

      {/* ── Main content ── */}
      <div className="card-enter" style={{
        position: 'relative', zIndex: 2,
        width: '100%', maxWidth: 420,
        margin: '0 20px',
        display: 'flex', flexDirection: 'column', alignItems: 'center',
      }}>

        {/* University name */}
        <p className="fade-in" style={{
          fontSize: 11, fontWeight: 600, letterSpacing: '2px',
          color: 'rgba(255,255,255,0.45)', textTransform: 'uppercase',
          marginBottom: 10, textAlign: 'center',
        }}>
          Bangladesh Army University of Science and Technology
        </p>

        {/* System name */}
        <h1 className="fade-in" style={{
          fontFamily: "'Playfair Display', serif",
          fontSize: 36, fontWeight: 700, color: '#fff',
          margin: '0 0 6px', textAlign: 'center', letterSpacing: '-0.5px',
        }}>
          LibraryMS
        </h1>

        <div style={{
          width: 40, height: 2,
          background: 'linear-gradient(90deg, transparent, #c9a84c, transparent)',
          margin: '0 auto 32px',
        }} />

        {/* ── Glass Card ── */}
        <div style={{
          width: '100%',
          background: 'rgba(15,15,25,0.65)',
          backdropFilter: 'blur(28px)',
          WebkitBackdropFilter: 'blur(28px)',
          border: '1px solid rgba(255,255,255,0.1)',
          borderRadius: 22,
          padding: '36px 34px 30px',
          boxShadow: '0 32px 80px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.08)',
        }}>
          <h2 style={{
            fontSize: 22, fontWeight: 700, color: '#fff',
            margin: '0 0 6px', textAlign: 'center',
          }}>Welcome back</h2>
          <p style={{
            fontSize: 13, color: 'rgba(255,255,255,0.38)',
            margin: '0 0 26px', textAlign: 'center', lineHeight: 1.5,
          }}>Sign in to access your library account</p>

          {/* Error */}
          {error && (
            <div style={{
              background: 'rgba(220,38,38,0.15)',
              border: '1px solid rgba(220,38,38,0.35)',
              color: '#fca5a5', padding: '11px 14px',
              borderRadius: 10, fontSize: 13,
              marginBottom: 18, display: 'flex',
              alignItems: 'center', gap: 8,
            }}>
              <span style={{ fontSize: 15 }}>⚠</span> {error}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            {/* Email */}
            <div style={{ marginBottom: 16 }}>
              <label style={{
                display: 'block', fontSize: 11, fontWeight: 700,
                color: 'rgba(255,255,255,0.5)', marginBottom: 8,
                letterSpacing: '1px', textTransform: 'uppercase',
              }}>Email Address</label>
              <input
                className="li"
                type="email"
                value={email}
                onChange={e => setEmail(e.target.value.toLowerCase())}
                placeholder="your@email.com"
                required
                style={{
                  width: '100%', padding: '13px 16px',
                  background: 'rgba(255,255,255,0.07)',
                  border: '1.5px solid rgba(255,255,255,0.12)',
                  borderRadius: 12, fontSize: 14,
                  color: '#fff', fontFamily: 'inherit',
                }}
              />
            </div>

            {/* Password */}
            <div style={{ marginBottom: 26 }}>
              <label style={{
                display: 'block', fontSize: 11, fontWeight: 700,
                color: 'rgba(255,255,255,0.5)', marginBottom: 8,
                letterSpacing: '1px', textTransform: 'uppercase',
              }}>Password</label>
              <div style={{ position: 'relative' }}>
                <input
                  className="li"
                  type={showPass ? 'text' : 'password'}
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  placeholder="••••••••"
                  required
                  style={{
                    width: '100%', padding: '13px 46px 13px 16px',
                    background: 'rgba(255,255,255,0.07)',
                    border: '1.5px solid rgba(255,255,255,0.12)',
                    borderRadius: 12, fontSize: 14,
                    color: '#fff', fontFamily: 'inherit',
                  }}
                />
                <button type="button" className="eye-btn" onClick={() => setShowPass(v => !v)}>
                  {showPass ? '🙈' : '👁'}
                </button>
              </div>
            </div>

            {/* Submit */}
            <button
              type="submit"
              disabled={loading}
              className="btn-sign"
              style={{
                width: '100%', padding: '14px',
                background: '#c9a84c', color: '#1a1a2e',
                border: 'none', borderRadius: 12,
                fontSize: 15, fontWeight: 700,
                cursor: 'pointer', fontFamily: 'inherit',
                letterSpacing: '0.3px', transition: 'all .25s',
                boxShadow: '0 4px 18px rgba(201,168,76,0.3)',
              }}>
              {loading ? 'Signing in...' : 'Sign In →'}
            </button>
          </form>

          {/* Register */}
          <p style={{
            textAlign: 'center', fontSize: 13,
            color: 'rgba(255,255,255,0.35)', marginTop: 20,
          }}>
            New student or staff?{' '}
            <Link to="/register" className="reg-link">Create Account</Link>
          </p>
        </div>

        {/* Footer */}
        <p style={{
          fontSize: 10, color: 'rgba(255,255,255,0.2)',
          marginTop: 20, letterSpacing: '1.5px',
          textTransform: 'uppercase', textAlign: 'center',
        }}>
          BAUST · Library Management System
        </p>
      </div>
    </div>
  );
}
